package com.alibaba.fastjson2.internal.processor;

import com.alibaba.fastjson2.util.Fnv;

import javax.lang.model.element.ExecutableElement;
import javax.lang.model.element.VariableElement;
import javax.lang.model.type.TypeMirror;

public class AttributeInfo
        implements Comparable<AttributeInfo> {
    final String name;
    final long nameHashCode;
    final TypeMirror type;
    VariableElement field;
    ExecutableElement getMethod;
    ExecutableElement setMethod;
    VariableElement argument;
    long readerFeatures;

    public AttributeInfo(
            String name,
            TypeMirror type,
            VariableElement field,
            ExecutableElement getMethod,
            ExecutableElement setMethod,
            VariableElement argument
    ) {
        this.name = name;
        this.nameHashCode = Fnv.hashCode64(name);
        this.type = type;
        this.field = field;
        this.getMethod = getMethod;
        this.setMethod = setMethod;
        this.argument = argument;
    }

    public boolean supportSet() {
        return field != null || setMethod != null;
    }

    @Override
    public int compareTo(AttributeInfo o) {
        return this.name.compareTo(o.name);
    }
}

package com.alibaba.fastjson2.filter;

import java.util.Arrays;

public class Labels {
    public static class DefaultLabelFilter
            implements LabelFilter {
        final String[] includes;
        final String[] excludes;

        public DefaultLabelFilter(String[] includes, String[] excludes) {
            if (includes != null) {
                this.includes = new String[includes.length];
                System.arraycopy(includes, 0, this.includes, 0, includes.length);
                Arrays.sort(this.includes);
            } else {
                this.includes = null;
            }

            if (excludes != null) {
                this.excludes = new String[excludes.length];
                System.arraycopy(excludes, 0, this.excludes, 0, excludes.length);
                Arrays.sort(this.excludes);
            } else {
                this.excludes = null;
            }
        }

        @Override
        public boolean apply(String label) {
            if (excludes != null) {
                return Arrays.binarySearch(excludes, label) < 0;
            }

            return includes != null && Arrays.binarySearch(includes, label) >= 0;
        }
    }

    public static LabelFilter includes(String... views) {
        return new DefaultLabelFilter(views, null);
    }

    public static LabelFilter excludes(String... views) {
        return new DefaultLabelFilter(null, views);
    }
}

package com.alibaba.fastjson2;

final class JSONPathSingleNameInteger
        extends JSONPathTyped {
    final long nameHashCode;
    final String name;

    public JSONPathSingleNameInteger(JSONPathSingleName jsonPath) {
        super(jsonPath, Integer.class);
        this.nameHashCode = jsonPath.nameHashCode;
        this.name = jsonPath.name;
    }

    @Override
    public Object extract(JSONReader jsonReader) {
        if (jsonReader.jsonb) {
            if (jsonReader.isObject()) {
                jsonReader.nextIfObjectStart();
                while (!jsonReader.nextIfObjectEnd()) {
                    long nameHashCode = jsonReader.readFieldNameHashCode();
                    if (nameHashCode == 0) {
                        continue;
                    }

                    boolean match = nameHashCode == this.nameHashCode;
                    if (!match && (!jsonReader.isObject()) && !jsonReader.isArray()) {
                        jsonReader.skipValue();
                        continue;
                    }

                    return jsonReader.readInt32();
                }
            }
        } else if (jsonReader.nextIfObjectStart()) {
            while (!jsonReader.nextIfObjectEnd()) {
                long nameHashCode = jsonReader.readFieldNameHashCode();
                boolean match = nameHashCode == this.nameHashCode;

                if (!match) {
                    jsonReader.skipValue();
                    continue;
                }

                return jsonReader.readInt32();
            }
        }

        return null;
    }
}

